commit 02e29ff698a824c619e9669e0b7020fe924d7084
Author: Josh Law <objecting@objecting.org>
Date:   Fri Mar 20 16:34:55 2026 +0000

    mm/damon/sysfs: check contexts->nr before accessing contexts_arr[0]

    Multiple sysfs command paths dereference contexts_arr[0] without first
    verifying that nr_contexts >= 1.  A user can set nr_contexts to 0 via
    sysfs while DAMON is running, causing NULL pointer dereferences.

    Guard all commands (except OFF) at the entry point of
    damon_sysfs_handle_cmd().

    Fixes: 0ac32b8affb5 ("mm/damon/sysfs: support DAMOS stats")
    Cc: <stable@vger.kernel.org>    # 5.18.x
    Signed-off-by: Josh Law <objecting@objecting.org>
    Reviewed-by: SeongJae Park <sj@kernel.org>

diff --git a/mm/damon/sysfs.c b/mm/damon/sysfs.c
index 576d1ddd736b..1f73e08b5a18 100644
--- a/mm/damon/sysfs.c
+++ b/mm/damon/sysfs.c
@@ -1747,6 +1747,9 @@ static int damon_sysfs_update_schemes_tried_regions(
 static int damon_sysfs_handle_cmd(enum damon_sysfs_cmd cmd,
 		struct damon_sysfs_kdamond *kdamond)
 {
+	if (cmd != DAMON_SYSFS_CMD_OFF && kdamond->contexts->nr != 1)
+		return -EINVAL;
+
 	switch (cmd) {
 	case DAMON_SYSFS_CMD_ON:
 		return damon_sysfs_turn_damon_on(kdamond);



